"country_name": "Netherlands",
"state_prov": "North Holland",
"city": "Amsterdam",
"latitude": "52.37403",
"longitude": "4.88969",
"is_eu": true
},
"asn": {
"as_number": "AS9009",
"organization": "M247 Europe SRL",
"type": "HOSTING"
},
"security": {
"threat_score": 78,
"is_vpn": true,
"vpn_provider_names": ["NordVPN"],
"vpn_confidence_score": 90,
"vpn_last_seen": "2026-07-13",
